/**
 * @summary Get activity logs
 */
export const getGetActivityLogsUrl = (params?: GetActivityLogsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/activity?${stringifiedParams}`
    : `/api/activity`;
};

export const getActivityLogs = async (
  params?: GetActivityLogsParams,
  options?: RequestInit,
): Promise<ActivityLog[]> => {
  return customFetch<ActivityLog[]>(getGetActivityLogsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetActivityLogsQueryKey = (params?: GetActivityLogsParams) => {
  return [`/api/activity`, ...(params ? [params] : [])] as const;
};

